/*
  # Update daily_content with correct videos and questions

  Replaces all placeholder data with the real content for days 0-22:
  - Correct YouTube embed URLs per day
  - Real daily quotes
  - Specific reflection questions per day
  - Insight prompts per day
  - Stage names per day
*/

ON CONFLICT (day_number) DO UPDATE SET
  stage_name = EXCLUDED.stage_name,
  video_embed_url = EXCLUDED.video_embed_url,
  daily_quote = EXCLUDED.daily_quote,
  questions_text = EXCLUDED.questions_text,
  insight_prompt_text = EXCLUDED.insight_prompt_text,
  is_published = EXCLUDED.is_published;
